/* =================================================================================================
FILE:         07_vw_sdi_pulseByod_silver_adobeByodEntryPages_weekly.sql
LAYER:        Silver View
DATASET:      prj-dbi-prd-1.ds_dbi_digitalmedia_automation
VIEW NAME:    vw_sdi_pulseByod_silver_adobeByodEntryPages_weekly

SOURCE:
  prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_adobe_silver_byodFlowEntryPagesByChannelGroupsPlusAll_Weekly

DESTINATION:
  prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_pulseByod_silver_adobeByodEntryPages_weekly

PURPOSE:
  Silver view for Adobe Analytics BYOD funnel entry page metrics.
  Outputs a WIDE table — one row per week_sun_to_sat.
  Pivots ChannelGroup rows into columns so each channel
  becomes its own set of prefixed metric columns.
  Applies WoW/LY comparisons and max_data_date.

  Entry page metrics track where BYOD visitors entered the site:
    byodUvnbVisitors                 — total unique non-bounced BYOD visitors
    byodEntryByodPageVisitors        — entered on BYOD page
    byodEntryHomePageVisitors        — entered on homepage
    byodEntryDevicePageVisitors      — entered on device page
    byodEntryPlansPageVisitors       — entered on plans page
    byodEntryOtherPageVisitors       — entered on other page (NEW: otherpage2 only — true residual)
    byodEntryStorePageVisitors       — entered on store page (NEW)
    byodEntryByodLandingPageVisitors — entered on BYOD landing page (NEW)
    byodEntryOffersSwitchVisitors    — entered on offers/switch page (NEW)

  -- OLD OTHER reference (not a live column):
  -- Old Other = byodEntryStorePageVisitors + byodEntryByodLandingPageVisitors
  --           + byodEntryOffersSwitchVisitors + byodEntryOtherPageVisitors (otherpage2)
  -- Previously sourced from: sdi_raw_adobe_byod_flow_{channel}_byod_entry_otherpage_visitors_weekly_tmo

BUSINESS GRAIN:
  One row per week_sun_to_sat

SOURCE GRAIN:
  One row per WeekSunSat + ChannelGroup
  ChannelGroup values: ALL, PAID SEARCH, ORGANIC SEARCH,
                       DIRECT, SOCIAL, PROGRAMMATIC, OTHER

COLUMN NAMING CONVENTION:
  adobe_{metric}_{channel}
  Channel suffixes: allChannels, paidSearch, organicSearch, direct, social, programmatic, other

BUSINESS LOGIC:
  - No derived/ratio metrics — all metrics are raw visitor counts
  - WoW: self-join on week_sun_to_sat - 7 days (gap-safe)
  - LY:  self-join on custom_week_num - 52 (gap-safe, Sun-to-Sat anchor)
  - wow_pct / yoy_pct as decimals — NULL when prior NULL or 0
  - max_data_date: latest week_sun_to_sat with any non-null metric

CUSTOM WEEK NUMBER:
  custom_week_num = DATE_DIFF(DATE_SUB(week_sun_to_sat, INTERVAL 6 DAY), DATE '2023-01-01', WEEK)
  LY match: current.custom_week_num - prior.custom_week_num = 52

DOWNSTREAM:
  Gold Wide : vw_sdi_pulseByod_gold_unified_wide
  Gold Long : vw_sdi_pulseByod_gold_unified_long

CHANGES:
  2026-06-XX — Other segregation:
               byodEntryOtherPageVisitors redefined to otherpage2 only (from upstream Bronze)
               Added byodEntryStorePageVisitors, byodEntryByodLandingPageVisitors,
               byodEntryOffersSwitchVisitors across all 7 channels with full WoW/LY/pct treatment
================================================================================================= */

CREATE OR REPLACE VIEW `prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_pulseByod_silver_adobeByodEntryPages_weekly`
AS

WITH base AS (
  SELECT
    WeekSunSat                         AS week_sun_to_sat,
    ChannelGroup,
    ByodUvnbVisitors,
    ByodEntryByodPageVisitors,
    ByodEntryHomePageVisitors,
    ByodEntryDevicePageVisitors,
    ByodEntryPlansPageVisitors,
    ByodEntryOtherPageVisitors,
    ByodEntryStorePageVisitors,          -- NEW
    ByodEntryByodLandingPageVisitors,    -- NEW
    ByodEntryOffersSwitchVisitors        -- NEW
  FROM `prj-dbi-prd-1.ds_dbi_digitalmedia_automation.vw_sdi_adobe_silver_byodFlowEntryPagesByChannelGroupsPlusAll_Weekly`
),

pivoted AS (
  SELECT
    week_sun_to_sat,
    -- ALL CHANNELS
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodUvnbVisitors END) AS adobe_byodUvnbVisitors_allChannels,
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodEntryByodPageVisitors END) AS adobe_byodEntryByodPageVisitors_allChannels,
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodEntryHomePageVisitors END) AS adobe_byodEntryHomePageVisitors_allChannels,
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodEntryDevicePageVisitors END) AS adobe_byodEntryDevicePageVisitors_allChannels,
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodEntryPlansPageVisitors END) AS adobe_byodEntryPlansPageVisitors_allChannels,
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodEntryOtherPageVisitors END) AS adobe_byodEntryOtherPageVisitors_allChannels,
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodEntryStorePageVisitors END) AS adobe_byodEntryStorePageVisitors_allChannels,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodEntryByodLandingPageVisitors END) AS adobe_byodEntryByodLandingPageVisitors_allChannels,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'ALL CHANNELS' THEN ByodEntryOffersSwitchVisitors END) AS adobe_byodEntryOffersSwitchVisitors_allChannels,  -- NEW
    -- PAID SEARCH
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodUvnbVisitors END) AS adobe_byodUvnbVisitors_paidSearch,
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodEntryByodPageVisitors END) AS adobe_byodEntryByodPageVisitors_paidSearch,
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodEntryHomePageVisitors END) AS adobe_byodEntryHomePageVisitors_paidSearch,
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodEntryDevicePageVisitors END) AS adobe_byodEntryDevicePageVisitors_paidSearch,
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodEntryPlansPageVisitors END) AS adobe_byodEntryPlansPageVisitors_paidSearch,
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodEntryOtherPageVisitors END) AS adobe_byodEntryOtherPageVisitors_paidSearch,
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodEntryStorePageVisitors END) AS adobe_byodEntryStorePageVisitors_paidSearch,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodEntryByodLandingPageVisitors END) AS adobe_byodEntryByodLandingPageVisitors_paidSearch,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'PAID SEARCH' THEN ByodEntryOffersSwitchVisitors END) AS adobe_byodEntryOffersSwitchVisitors_paidSearch,  -- NEW
    -- ORGANIC SEARCH
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodUvnbVisitors END) AS adobe_byodUvnbVisitors_organicSearch,
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodEntryByodPageVisitors END) AS adobe_byodEntryByodPageVisitors_organicSearch,
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodEntryHomePageVisitors END) AS adobe_byodEntryHomePageVisitors_organicSearch,
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodEntryDevicePageVisitors END) AS adobe_byodEntryDevicePageVisitors_organicSearch,
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodEntryPlansPageVisitors END) AS adobe_byodEntryPlansPageVisitors_organicSearch,
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodEntryOtherPageVisitors END) AS adobe_byodEntryOtherPageVisitors_organicSearch,
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodEntryStorePageVisitors END) AS adobe_byodEntryStorePageVisitors_organicSearch,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodEntryByodLandingPageVisitors END) AS adobe_byodEntryByodLandingPageVisitors_organicSearch,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'ORGANIC SEARCH' THEN ByodEntryOffersSwitchVisitors END) AS adobe_byodEntryOffersSwitchVisitors_organicSearch,  -- NEW
    -- DIRECT
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodUvnbVisitors END) AS adobe_byodUvnbVisitors_direct,
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodEntryByodPageVisitors END) AS adobe_byodEntryByodPageVisitors_direct,
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodEntryHomePageVisitors END) AS adobe_byodEntryHomePageVisitors_direct,
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodEntryDevicePageVisitors END) AS adobe_byodEntryDevicePageVisitors_direct,
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodEntryPlansPageVisitors END) AS adobe_byodEntryPlansPageVisitors_direct,
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodEntryOtherPageVisitors END) AS adobe_byodEntryOtherPageVisitors_direct,
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodEntryStorePageVisitors END) AS adobe_byodEntryStorePageVisitors_direct,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodEntryByodLandingPageVisitors END) AS adobe_byodEntryByodLandingPageVisitors_direct,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'DIRECT' THEN ByodEntryOffersSwitchVisitors END) AS adobe_byodEntryOffersSwitchVisitors_direct,  -- NEW
    -- SOCIAL
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodUvnbVisitors END) AS adobe_byodUvnbVisitors_social,
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodEntryByodPageVisitors END) AS adobe_byodEntryByodPageVisitors_social,
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodEntryHomePageVisitors END) AS adobe_byodEntryHomePageVisitors_social,
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodEntryDevicePageVisitors END) AS adobe_byodEntryDevicePageVisitors_social,
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodEntryPlansPageVisitors END) AS adobe_byodEntryPlansPageVisitors_social,
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodEntryOtherPageVisitors END) AS adobe_byodEntryOtherPageVisitors_social,
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodEntryStorePageVisitors END) AS adobe_byodEntryStorePageVisitors_social,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodEntryByodLandingPageVisitors END) AS adobe_byodEntryByodLandingPageVisitors_social,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'SOCIAL' THEN ByodEntryOffersSwitchVisitors END) AS adobe_byodEntryOffersSwitchVisitors_social,  -- NEW
    -- PROGRAMMATIC
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodUvnbVisitors END) AS adobe_byodUvnbVisitors_programmatic,
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodEntryByodPageVisitors END) AS adobe_byodEntryByodPageVisitors_programmatic,
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodEntryHomePageVisitors END) AS adobe_byodEntryHomePageVisitors_programmatic,
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodEntryDevicePageVisitors END) AS adobe_byodEntryDevicePageVisitors_programmatic,
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodEntryPlansPageVisitors END) AS adobe_byodEntryPlansPageVisitors_programmatic,
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodEntryOtherPageVisitors END) AS adobe_byodEntryOtherPageVisitors_programmatic,
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodEntryStorePageVisitors END) AS adobe_byodEntryStorePageVisitors_programmatic,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodEntryByodLandingPageVisitors END) AS adobe_byodEntryByodLandingPageVisitors_programmatic,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'PROGRAMMATIC' THEN ByodEntryOffersSwitchVisitors END) AS adobe_byodEntryOffersSwitchVisitors_programmatic,  -- NEW
    -- OTHER
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodUvnbVisitors END) AS adobe_byodUvnbVisitors_other,
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodEntryByodPageVisitors END) AS adobe_byodEntryByodPageVisitors_other,
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodEntryHomePageVisitors END) AS adobe_byodEntryHomePageVisitors_other,
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodEntryDevicePageVisitors END) AS adobe_byodEntryDevicePageVisitors_other,
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodEntryPlansPageVisitors END) AS adobe_byodEntryPlansPageVisitors_other,
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodEntryOtherPageVisitors END) AS adobe_byodEntryOtherPageVisitors_other,
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodEntryStorePageVisitors END) AS adobe_byodEntryStorePageVisitors_other,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodEntryByodLandingPageVisitors END) AS adobe_byodEntryByodLandingPageVisitors_other,  -- NEW
    MAX(CASE WHEN ChannelGroup = 'OTHER' THEN ByodEntryOffersSwitchVisitors END) AS adobe_byodEntryOffersSwitchVisitors_other,  -- NEW
  FROM base
  GROUP BY week_sun_to_sat
),

with_week_num AS (
  SELECT
    *,
    DATE_DIFF(DATE_SUB(week_sun_to_sat, INTERVAL 6 DAY), DATE '2023-01-01', WEEK) AS custom_week_num
  FROM pivoted
),

with_comparisons AS (
  SELECT
    c.week_sun_to_sat, c.custom_week_num,
    -- ALL CHANNELS
    c.adobe_byodUvnbVisitors_allChannels, w.adobe_byodUvnbVisitors_allChannels AS adobe_byodUvnbVisitors_allChannels_wow, l.adobe_byodUvnbVisitors_allChannels AS adobe_byodUvnbVisitors_allChannels_ly,
    c.adobe_byodEntryByodPageVisitors_allChannels, w.adobe_byodEntryByodPageVisitors_allChannels AS adobe_byodEntryByodPageVisitors_allChannels_wow, l.adobe_byodEntryByodPageVisitors_allChannels AS adobe_byodEntryByodPageVisitors_allChannels_ly,
    c.adobe_byodEntryHomePageVisitors_allChannels, w.adobe_byodEntryHomePageVisitors_allChannels AS adobe_byodEntryHomePageVisitors_allChannels_wow, l.adobe_byodEntryHomePageVisitors_allChannels AS adobe_byodEntryHomePageVisitors_allChannels_ly,
    c.adobe_byodEntryDevicePageVisitors_allChannels, w.adobe_byodEntryDevicePageVisitors_allChannels AS adobe_byodEntryDevicePageVisitors_allChannels_wow, l.adobe_byodEntryDevicePageVisitors_allChannels AS adobe_byodEntryDevicePageVisitors_allChannels_ly,
    c.adobe_byodEntryPlansPageVisitors_allChannels, w.adobe_byodEntryPlansPageVisitors_allChannels AS adobe_byodEntryPlansPageVisitors_allChannels_wow, l.adobe_byodEntryPlansPageVisitors_allChannels AS adobe_byodEntryPlansPageVisitors_allChannels_ly,
    c.adobe_byodEntryOtherPageVisitors_allChannels, w.adobe_byodEntryOtherPageVisitors_allChannels AS adobe_byodEntryOtherPageVisitors_allChannels_wow, l.adobe_byodEntryOtherPageVisitors_allChannels AS adobe_byodEntryOtherPageVisitors_allChannels_ly,
