    c.adobe_byodEntryByodLandingPageVisitors_allChannels, w.adobe_byodEntryByodLandingPageVisitors_allChannels AS adobe_byodEntryByodLandingPageVisitors_allChannels_wow, l.adobe_byodEntryByodLandingPageVisitors_allChannels AS adobe_byodEntryByodLandingPageVisitors_allChannels_ly,
    c.adobe_byodEntryOffersSwitchVisitors_allChannels, w.adobe_byodEntryOffersSwitchVisitors_allChannels AS adobe_byodEntryOffersSwitchVisitors_allChannels_wow, l.adobe_byodEntryOffersSwitchVisitors_allChannels AS adobe_byodEntryOffersSwitchVisitors_allChannels_ly,
