    c.adobe_byodEntryStorePageVisitors_paidSearch, w.adobe_byodEntryStorePageVisitors_paidSearch AS adobe_byodEntryStorePageVisitors_paidSearch_wow, l.adobe_byodEntryStorePageVisitors_paidSearch AS adobe_byodEntryStorePageVisitors_paidSearch_ly,
    c.adobe_byodEntryByodLandingPageVisitors_paidSearch, w.adobe_byodEntryByodLandingPageVisitors_paidSearch AS adobe_byodEntryByodLandingPageVisitors_paidSearch_wow, l.adobe_byodEntryByodLandingPageVisitors_paidSearch AS adobe_byodEntryByodLandingPageVisitors_paidSearch_ly,
