    c.adobe_byodEntryByodLandingPageVisitors_programmatic, w.adobe_byodEntryByodLandingPageVisitors_programmatic AS adobe_byodEntryByodLandingPageVisitors_programmatic_wow, l.adobe_byodEntryByodLandingPageVisitors_programmatic AS adobe_byodEntryByodLandingPageVisitors_programmatic_ly,
