    adobe_byodEntryHomePageVisitors_paidSearch, adobe_byodEntryHomePageVisitors_paidSearch_wow, adobe_byodEntryHomePageVisitors_paidSearch_ly, CASE WHEN adobe_byodEntryHomePageVisitors_paidSearch_wow IS NULL OR adobe_byodEntryHomePageVisitors_paidSearch_wow = 0 THEN NULL ELSE ROUND((adobe_byodEntryHomePageVisitors_paidSearch - adobe_byodEntryHomePageVisitors_paidSearch_wow) / adobe_byodEntryHomePageVisitors_paidSearch_wow, 6) END AS adobe_byodEntryHomePageVisitors_paidSearch_wow_pct, CASE WHEN adobe_byodEntryHomePageVisitors_paidSearch_ly  IS NULL OR adobe_byodEntryHomePageVisitors_paidSearch_ly  = 0 THEN NULL ELSE ROUND((adobe_byodEntryHomePageVisitors_paidSearch - adobe_byodEntryHomePageVisitors_paidSearch_ly)  / adobe_byodEntryHomePageVisitors_paidSearch_ly,  6) END AS adobe_byodEntryHomePageVisitors_paidSearch_yoy_pct,
